"""Presentation helpers for launch flow output."""

from __future__ import annotations

from rich.console import Console

from scc_cli.application.launch.output_models import (
    LaunchInfoEvent,
    LaunchOutputViewModel,
    LaunchSuccessEvent,
    LaunchWarningEvent,
)
from scc_cli.application.start_session import StartSessionPlan
from scc_cli.panels import create_warning_panel
from scc_cli.theme import Indicators
from scc_cli.ui.chrome import print_with_layout


def build_sync_output_view_model(plan: StartSessionPlan) -> LaunchOutputViewModel:
    """Build output view model for marketplace sync messages.

    Invariants:
        - Messages mirror existing CLI text for sync warnings and counts.

    Args:
        plan: Start session plan with sync result metadata.

    Returns:
        LaunchOutputViewModel describing sync output to render.
    """
    events: list[LaunchInfoEvent | LaunchWarningEvent | LaunchSuccessEvent] = []
    if plan.sync_result and plan.sync_result.warnings:
        for warning in plan.sync_result.warnings:
            events.append(LaunchWarningEvent(message=warning))
    if plan.sync_result and plan.sync_result.plugins_enabled:
        events.append(
            LaunchSuccessEvent(
                message=(
                    f"{Indicators.get('PASS')} Enabled "
                    f"{len(plan.sync_result.plugins_enabled)} team plugin(s)"
                )
            )
        )
    if plan.sync_result and plan.sync_result.marketplaces_materialized:
        events.append(
            LaunchSuccessEvent(
                message=(
                    f"{Indicators.get('PASS')} Materialized "
                    f"{len(plan.sync_result.marketplaces_materialized)} marketplace(s)"
                )
            )
        )
    return LaunchOutputViewModel(
        events=events,
        sync_result=plan.sync_result,
        sync_error_message=plan.sync_error_message,
    )


def render_launch_output(
    view_model: LaunchOutputViewModel,
    *,
    console: Console,
    json_mode: bool,
) -> None:
    """Render launch output events at the CLI edge.

    Args:
        view_model: Launch output view model.
        console: Console for rendering.
        json_mode: Whether JSON output is enabled (suppresses human output).
    """
    if json_mode:
        return
    if view_model.sync_error_message:
        panel = create_warning_panel(
            "Marketplace Sync Failed",
            view_model.sync_error_message,
            "Team plugins may not be available. Use --dry-run to diagnose.",
        )
        print_with_layout(console, panel, constrain=True)
        return
    if not view_model.events:
        return
    console.print()
    for event in view_model.events:
        if isinstance(event, LaunchWarningEvent):
            print_with_layout(console, f"[yellow]{event.message}[/yellow]")
        else:
            print_with_layout(console, f"[green]{event.message}[/green]")
    console.print()

"""Sandbox runtime port definition."""

from __future__ import annotations

from typing import Protocol

from scc_cli.ports.models import SandboxHandle, SandboxSpec, SandboxStatus


class SandboxRuntime(Protocol):
    """Abstract sandbox runtime operations."""

    def ensure_available(self) -> None:
        """Ensure the runtime is available and ready for use."""

    def run(self, spec: SandboxSpec) -> SandboxHandle:
        """Launch a sandbox session for the given spec."""

    def resume(self, handle: SandboxHandle) -> None:
        """Resume a stopped sandbox session."""

    def stop(self, handle: SandboxHandle) -> None:
        """Stop a running sandbox session."""

    def remove(self, handle: SandboxHandle) -> None:
        """Remove a sandbox session."""

    def list_running(self) -> list[SandboxHandle]:
        """List running sandbox sessions."""

    def status(self, handle: SandboxHandle) -> SandboxStatus:
        """Return status details for a sandbox session."""

"""Docker sandbox runtime adapter for SandboxRuntime port."""

from __future__ import annotations

from scc_cli import docker
from scc_cli.core.enums import NetworkPolicy
from scc_cli.core.network_policy import collect_proxy_env
from scc_cli.ports.models import SandboxHandle, SandboxSpec, SandboxState, SandboxStatus
from scc_cli.ports.sandbox_runtime import SandboxRuntime


def _extract_container_name(cmd: list[str]) -> str | None:
    for idx, arg in enumerate(cmd):
        if arg == "--name" and idx + 1 < len(cmd):
            return cmd[idx + 1]
        if arg.startswith("--name="):
            return arg.split("=", 1)[1]
    if cmd and cmd[-1].startswith("scc-"):
        return cmd[-1]
    return None


class DockerSandboxRuntime(SandboxRuntime):
    """SandboxRuntime backed by Docker sandbox CLI."""

    def ensure_available(self) -> None:
        docker.check_docker_available()

    def run(self, spec: SandboxSpec) -> SandboxHandle:
        docker.prepare_sandbox_volume_for_credentials()
        env_vars = dict(spec.env) if spec.env else {}
        if spec.network_policy == NetworkPolicy.WEB_EGRESS_ENFORCED.value:
            for key, value in collect_proxy_env().items():
                env_vars.setdefault(key, value)
        runtime_env = env_vars or None
        docker_cmd, _is_resume = docker.get_or_create_container(
            workspace=spec.workspace_mount.source,
            branch=None,
            profile=None,
            force_new=spec.force_new,
            continue_session=spec.continue_session,
            env_vars=runtime_env,
        )
        container_name = _extract_container_name(docker_cmd)
        plugin_settings = spec.agent_settings.content if spec.agent_settings else None
        docker.run(
            docker_cmd,
            org_config=spec.org_config,
            container_workdir=spec.workdir,
            plugin_settings=plugin_settings,
            env_vars=runtime_env,
        )
        return SandboxHandle(
            sandbox_id=container_name or "sandbox",
            name=container_name,
        )

    def resume(self, handle: SandboxHandle) -> None:
        docker.resume_container(handle.sandbox_id)

    def stop(self, handle: SandboxHandle) -> None:
        docker.stop_container(handle.sandbox_id)

    def remove(self, handle: SandboxHandle) -> None:
        docker.remove_container(handle.sandbox_id, force=True)

    def list_running(self) -> list[SandboxHandle]:
        return [
            SandboxHandle(sandbox_id=container.id, name=container.name)
            for container in docker.list_running_sandboxes()
        ]

    def status(self, handle: SandboxHandle) -> SandboxStatus:
        status = docker.get_container_status(handle.sandbox_id)
        if not status:
            return SandboxStatus(state=SandboxState.UNKNOWN)
        normalized = status.lower()
        if "up" in normalized or "running" in normalized:
            state = SandboxState.RUNNING
        elif "exited" in normalized or "stopped" in normalized:
            state = SandboxState.STOPPED
        else:
            state = SandboxState.UNKNOWN
        return SandboxStatus(state=state)

